 1	import React, { FC } from 'react';
 2	
 3	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { getVMSSHSecretName } from '@kubevirt-utils/resources/vm';
 6	import { isEmpty } from '@kubevirt-utils/utils/utils';
 7	import { ClipboardCopy } from '@patternfly/react-core';
 8	
 9	import { getConsoleVirtctlCommand } from '../utils';
10	
11	type VirtctlSSHCommandClipboardCopyProps = {
12	  vm: V1VirtualMachine;
13	};
14	
15	const VirtctlSSHCommandClipboardCopy: FC<VirtctlSSHCommandClipboardCopyProps> = ({ vm }) => {
16	  const { t } = useKubevirtTranslation();
17	
18	  const sshSecretNotConfigured = isEmpty(getVMSSHSecretName(vm));
19	
20	  if (sshSecretNotConfigured) {
21	    return <div className="pf-v6-u-font-size-xs">{t('SSH secret not configured')}</div>;
22	  }
23	
24	  return (
25	    <ClipboardCopy
26	      clickTip={t('Copied')}
27	      data-test="ssh-over-virtctl"
28	      hoverTip={t('Copy to clipboard')}
29	    >
30	      {getConsoleVirtctlCommand(vm)}
31	    </ClipboardCopy>
32	  );
33	};
34	
35	export default VirtctlSSHCommandClipboardCopy;

