  1	import produce from 'immer';
  2	
  3	import { ServiceModel } from '@kubevirt-ui/kubevirt-api/console';
  4	import VirtualMachineInstanceModel from '@kubevirt-ui/kubevirt-api/console/models/VirtualMachineInstanceModel';
  5	import VirtualMachineModel from '@kubevirt-ui/kubevirt-api/console/models/VirtualMachineModel';
  6	import { IoK8sApiCoreV1Service } from '@kubevirt-ui/kubevirt-api/kubernetes';
  7	import { V1VirtualMachine, V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
  8	import { getCloudInitCredentials } from '@kubevirt-utils/resources/vmi';
  9	import { ensurePath, getRandomChars, isEmpty } from '@kubevirt-utils/utils/utils';
 10	import {
 11	  k8sCreate,
 12	  k8sDelete,
 13	  K8sResourceCommon,
 14	  k8sUpdate,
 15	} from '@openshift-console/dynamic-plugin-sdk';
 16	
 17	import { buildOwnerReference, getName, getNamespace } from './../../resources/shared';
 18	import { PORT, SERVICE_TYPES, SSH_PORT, VM_LABEL_AS_SSH_SERVICE_SELECTOR } from './constants';
 19	
 20	const buildSSHServiceFromVM = (vm: V1VirtualMachine, type: SERVICE_TYPES) => ({
 21	  apiVersion: ServiceModel.apiVersion,
 22	  kind: ServiceModel.kind,
 23	  metadata: {
 24	    // max name length is 63 characters
 25	    name: `${vm?.metadata?.name}-${type.toLowerCase()}-ssh-service`
 26	      .substring(0, 56)
 27	      .concat(`-${getRandomChars(4)}`),
 28	    namespace: vm?.metadata?.namespace,
 29	    ownerReferences: [buildOwnerReference(vm, { blockOwnerDeletion: false })],
 30	  },
 31	  spec: {
 32	    ports: [
 33	      {
 34	        port: PORT,
 35	        targetPort: SSH_PORT,
 36	      },
 37	    ],
 38	    selector: {
 39	      [VM_LABEL_AS_SSH_SERVICE_SELECTOR]: vm?.metadata?.name,
 40	    },
 41	    type,
 42	  },
 43	});
 44	
 45	export const deleteSSHService = (sshService: IoK8sApiCoreV1Service) =>
 46	  k8sDelete<IoK8sApiCoreV1Service>({
 47	    model: ServiceModel,
 48	    name: sshService?.metadata?.name,
 49	    ns: sshService?.metadata?.namespace,
 50	    resource: sshService,
 51	  });
 52	
 53	export const addSSHSelectorLabelToVM = async (
 54	  vm: V1VirtualMachine,
 55	  vmi: V1VirtualMachineInstance,
 56	  labelValue,
 57	) => {
 58	  const vmWithLabel = produce(vm, (draftVM) => {
 59	    ensurePath(draftVM, 'spec.template.metadata.labels');
 60	
 61	    draftVM.spec.template.metadata.labels[VM_LABEL_AS_SSH_SERVICE_SELECTOR] = labelValue;
 62	  });
 63	
 64	  if (vmi) {
 65	    const vmiWithLabel = produce(vmi, (draftVMI) => {
 66	      ensurePath(draftVMI, 'metadata.labels');
 67	
 68	      draftVMI.metadata.labels[VM_LABEL_AS_SSH_SERVICE_SELECTOR] = labelValue;
 69	    });
 70	
 71	    await k8sUpdate<V1VirtualMachineInstance>({
 72	      data: vmiWithLabel,
 73	      model: VirtualMachineInstanceModel,
 74	      name: vmiWithLabel?.metadata?.name,
 75	      ns: vmiWithLabel?.metadata?.namespace,
 76	    });
 77	  }
 78	
 79	  return k8sUpdate<V1VirtualMachine>({
 80	    data: vmWithLabel,
 81	    model: VirtualMachineModel,
 82	    name: vmWithLabel?.metadata?.name,
 83	    ns: vmWithLabel?.metadata?.namespace,
 84	  });
 85	};
 86	
 87	export const createSSHService = async (
 88	  vm: V1VirtualMachine,
 89	  type: SERVICE_TYPES,
 90	): Promise<K8sResourceCommon> => {
 91	  const serviceResource = buildSSHServiceFromVM(vm, type);
 92	
 93	  return k8sCreate({
 94	    data: serviceResource,
 95	    model: ServiceModel,
 96	    ns: getNamespace(vm),
 97	  });
 98	};
 99	
100	export const getConsoleVirtctlCommand = (vm: V1VirtualMachine, identityFlag?: string) => {
101	  const [vmName, vmNamespace, userName] = [
102	    getName(vm),
103	    getNamespace(vm),
104	    getCloudInitCredentials(vm)?.users?.[0]?.name,
105	  ];
106	
107	  return `virtctl -n ${vmNamespace} ssh ${userName}@${vmName} ${
108	    !isEmpty(identityFlag) ? identityFlag : '--identity-file=<path_to_sshkey>'
109	  }`;
110	};

